import unittestimport spacyimport loggingfrom lm_service.graph import dep_tree_from_phrase, excise_nodelogger = logging.getLogger(__name__)class TestR(unittest.TestCase):    nlp = spacy.load("en_core_web_trf")    phrases = [        "Peter would have caught the fish with a fishing rod, if not the"        " darkness. ",    ]    def test_excise(self):        rdoc, nx_graph = dep_tree_from_phrase(self.nlp, self.phrases[0])        excise_node(nx_graph, 9)        self.assertEqual(            len(nx_graph.edges),            14,        )        self.assertEqual(            len(nx_graph.nodes),            15,        )if __name__ == "__main__":    unittest.main()